public class AutoConfigurator {
    private Set<String> availableLibraries;
    private Map<String, String> appliedConfigs = new LinkedHashMap<>();

    public AutoConfigurator(String... libraries) {
        this.availableLibraries = new HashSet<>(Arrays.asList(libraries));
    }

    public void configure() {
